for pod in mongodb-replica-0 mongodb-replica-1 mongodb-replica-2; do
  echo "=== $pod ==="
  kubectl exec -n mongodb $pod -- mongosh --port 27017 -u admin-user -p admin123password --authenticationDatabase admin --quiet --eval "
    var r1 = db.adminCommand({setParameter: 1, logLevel: 3});
    var r2 = db.adminCommand({setParameter: 1, slowOpThresholdMs: 800});
    print('logLevel: ' + tojson(r1.ok) + ', slowOpThresholdMs: ' + tojson(r2.ok));
  " 2>/dev/null
done

